"use strict";(globalThis.webpackChunkself_healing_nixos_infra=globalThis.webpackChunkself_healing_nixos_infra||[]).push([[8239],{8404(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"\u5f53\u524d\u7248\u672c","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/self-healing-nixos-infra/zh/","label":"\u7b80\u4ecb","docId":"intro","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/architecture","label":"\u67b6\u6784\u6982\u89c8","docId":"architecture","unlisted":false},{"type":"category","label":"\u5f15\u5bfc\u4e0e\u6587\u4ef6\u7cfb\u7edf","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/bootstrap-nixos-anywhere","label":"\u4f7f\u7528 nixos-anywhere \u5f15\u5bfc\u5b89\u88c5","docId":"bootstrap-nixos-anywhere","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/btrfs-layout","label":"Btrfs & \u65e0\u72b6\u6001\u5316\u5e03\u5c40","docId":"btrfs-layout","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/btrfs-snapshots","label":"Btrfs \u5feb\u7167\u4e0e Snapper","docId":"btrfs-snapshots","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"AI \u57fa\u7840\u8bbe\u65bd\u7ba1\u7406","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/install-openclaw","label":"\u5b89\u88c5 OpenClaw","docId":"install-openclaw","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/ai-managed-infra","label":"AI \u7ba1\u7406\u7684\u57fa\u7840\u8bbe\u65bd","docId":"ai-managed-infra","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/context-management","label":"OpenClaw \u4e0a\u4e0b\u6587\u7ba1\u7406","docId":"context-management","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"\u5b89\u5168\u4e0e\u6062\u590d","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/totp-sudo-protection","label":"TOTP Sudo \u9632\u62a4","docId":"totp-sudo-protection","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/database-snapshot-strategy","label":"\u6570\u636e\u5e93\u5feb\u7167\u7b56\u7565","docId":"database-snapshot-strategy","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/disaster-recovery","label":"\u707e\u96be\u6062\u590d","docId":"disaster-recovery","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/ai-safety-and-rollback","label":"AI \u5b89\u5168\u4e0e\u56de\u6eda","docId":"ai-safety-and-rollback","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Production Operations","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/monitoring-alerting","label":"\u76d1\u63a7\u4e0e\u544a\u8b66","docId":"monitoring-alerting","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/impermanence-setup","label":"Impermanence \u8bbe\u7f6e","docId":"impermanence-setup","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/security-hardening","label":"\u5b89\u5168\u52a0\u56fa","docId":"security-hardening","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/faq","label":"\u5e38\u89c1\u95ee\u9898","docId":"faq","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/self-healing-nixos-infra/zh/interactive-demo","label":"\u4ea4\u4e92\u5f0f\u6f14\u793a","docId":"interactive-demo","unlisted":false}]},"docs":{"ai-managed-infra":{"id":"ai-managed-infra","title":"AI \u7ba1\u7406\u7684\u57fa\u7840\u8bbe\u65bd","description":"With OpenClaw installed, this chapter defines the operational model: what the AI manages autonomously, what requires human approval, and how the entire change pipeline works.","sidebar":"tutorialSidebar"},"ai-safety-and-rollback":{"id":"ai-safety-and-rollback","title":"AI \u5b89\u5168\u4e0e\u56de\u6eda","description":"This final chapter defines the operating procedures for running AI-managed infrastructure safely. It covers guardrails, rollback workflows, failure budgets, and the principles that keep humans in control while benefiting from AI automation.","sidebar":"tutorialSidebar"},"architecture":{"id":"architecture","title":"\u67b6\u6784\u6982\u89c8","description":"\u672c\u9875\u63cf\u8ff0\u4e86\u5b8c\u6574\u7684\u7cfb\u7edf\u67b6\u6784\u3001\u7ec4\u4ef6\u4ea4\u4e92\u3001\u6570\u636e\u6d41\u4ee5\u53ca\u6545\u969c\u5904\u7406\u7b56\u7565\u3002","sidebar":"tutorialSidebar"},"bootstrap-nixos-anywhere":{"id":"bootstrap-nixos-anywhere","title":"\u4f7f\u7528 nixos-anywhere \u5f15\u5bfc\u5b89\u88c5","description":"nixos-anywhere lets you install NixOS on any Linux server with root SSH access \u2014 no ISO image, no console access, no provider-specific tooling. It works by kexec-ing into a NixOS installer in RAM, partitioning the disk, and installing your declared configuration.","sidebar":"tutorialSidebar"},"btrfs-layout":{"id":"btrfs-layout","title":"Btrfs & \u65e0\u72b6\u6001\u5316\u5e03\u5c40","description":"A well-designed subvolume layout is the foundation of a rollback-capable system. Each subvolume can be independently snapshotted, mounted with different options, and excluded from rollbacks when persistence is needed.","sidebar":"tutorialSidebar"},"btrfs-snapshots":{"id":"btrfs-snapshots","title":"Btrfs \u5feb\u7167\u4e0e Snapper","description":"Snapshots are the core of the rollback strategy. This chapter covers manual snapshots, automated management with Snapper, and pre-rebuild hooks that ensure every system change has a restore point.","sidebar":"tutorialSidebar"},"context-management":{"id":"context-management","title":"OpenClaw \u4e0a\u4e0b\u6587\u7ba1\u7406","description":"\u5982\u679c\u6ca1\u6709\u4e0a\u4e0b\u6587\u7ba1\u7406\uff0c\u6bcf\u4e2a\u76d1\u63a7\u5468\u671f\u90fd\u662f\u4e00\u5f20\u767d\u7eb8 \u2014\u2014 OpenClaw \u770b\u5230\u4e00\u4e2a\u9ad8\u5185\u5b58\u544a\u8b66\uff0c\u5374\u5bf9\u8fc7\u53bb 30 \u5206\u949f\u5185\u4e0d\u65ad\u6500\u5347\u7684\u5185\u5b58\u589e\u957f\u4e00\u65e0\u6240\u77e5\u3002\u672c\u7ae0\u8bbe\u8ba1\u4e86\u4e0a\u4e0b\u6587\u5c42\uff0c\u8d4b\u4e88 OpenClaw \u8bb0\u5fc6\u3001\u8fde\u7eed\u6027\u4ee5\u53ca\u4ece\u8fc7\u5f80\u64cd\u4f5c\u4e2d\u5b66\u4e60\u7684\u80fd\u529b\u3002","sidebar":"tutorialSidebar"},"database-snapshot-strategy":{"id":"database-snapshot-strategy","title":"\u6570\u636e\u5e93\u5feb\u7167\u7b56\u7565","description":"Databases require special snapshot handling. A naive filesystem snapshot of a running database can capture an inconsistent state \u2014 half-written transactions, dirty buffers, incomplete WAL entries. This chapter covers strategies for consistent database snapshots on Btrfs.","sidebar":"tutorialSidebar"},"disaster-recovery":{"id":"disaster-recovery","title":"\u707e\u96be\u6062\u590d","description":"This chapter is the runbook. It covers every major failure scenario, the detection method, and step-by-step recovery procedures. Print this page and keep it accessible \u2014 you\'ll need it when things go wrong.","sidebar":"tutorialSidebar"},"faq":{"id":"faq","title":"\u5e38\u89c1\u95ee\u9898","description":"Btrfs \u4e0e\u5feb\u7167","sidebar":"tutorialSidebar"},"impermanence-setup":{"id":"impermanence-setup","title":"Impermanence \u8bbe\u7f6e","description":"Impermanence \u786e\u4fdd\u60a8\u7684 NixOS \u6839\u6587\u4ef6\u7cfb\u7edf\u5728\u6bcf\u6b21\u542f\u52a8\u65f6\u90fd\u88ab\u5f7b\u5e95\u6e05\u9664\u3002\u53ea\u6709\u88ab\u660e\u786e\u58f0\u660e\u6301\u4e45\u5316\u7684\u72b6\u6001\u624d\u4f1a\u4fdd\u7559\u3002\u8fd9\u6d88\u9664\u4e86\u914d\u7f6e\u6f02\u79fb\uff0c\u786e\u4fdd\u4e86\u53ef\u91cd\u73b0\u6027\uff0c\u5e76\u4f7f\u7cfb\u7edf\u771f\u6b63\u5b9e\u73b0\u58f0\u660e\u5f0f\u7ba1\u7406\u3002","sidebar":"tutorialSidebar"},"install-openclaw":{"id":"install-openclaw","title":"\u5b89\u88c5 OpenClaw","description":"OpenClaw is an AI-powered infrastructure operator. It monitors system health, proposes configuration changes, and can execute approved operations \u2014 all within a policy-defined boundary. Think of it as an AI SRE agent that works alongside your existing NixOS tooling.","sidebar":"tutorialSidebar"},"interactive-demo":{"id":"interactive-demo","title":"\u4ea4\u4e92\u5f0f\u6f14\u793a","description":"\u901a\u8fc7\u4ea4\u4e92\u5f0f\u6f14\u793a\u4f53\u9a8c\u81ea\u6108 NixOS \u57fa\u7840\u8bbe\u65bd\u7684\u5b9e\u9645\u8fd0\u4f5c\u3002\u8fd9\u4e9b\u6f14\u793a\u5c06\u672c\u6559\u7a0b\u4e2d\u6db5\u76d6\u7684\u6838\u5fc3\u6982\u5ff5\u53ef\u89c6\u5316\u5448\u73b0\u3002","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"\u7b80\u4ecb","description":"\u672c\u6559\u7a0b\u5c06\u5f15\u5bfc\u60a8\u6784\u5efa\u4e00\u4e2a\u751f\u4ea7\u7ea7\u3001\u53ef\u81ea\u6108\u7684\u670d\u52a1\u5668\uff0c\u5b83\u7ed3\u5408\u4e86\u58f0\u660e\u5f0f\u7cfb\u7edf\u7ba1\u7406\u3001\u5199\u65f6\u590d\u5236\u5feb\u7167\u3001AI \u8f85\u52a9\u64cd\u4f5c\u4ee5\u53ca\u53d7 TOTP \u4fdd\u62a4\u7684\u5173\u952e\u547d\u4ee4\u3002","sidebar":"tutorialSidebar"},"monitoring-alerting":{"id":"monitoring-alerting","title":"\u76d1\u63a7\u4e0e\u544a\u8b66","description":"OpenClaw \u9700\u8981\u53ef\u89c2\u6d4b\u6027\u6570\u636e\u6765\u68c0\u6d4b\u95ee\u9898\u5e76\u63d0\u51fa\u4fee\u590d\u65b9\u6848\u3002\u5982\u679c\u6ca1\u6709\u9002\u5f53\u7684\u76d1\u63a7\uff0cAI \u64cd\u4f5c\u4ee3\u7406\u5c31\u5982\u540c\u76f2\u4eba\u6478\u8c61\u3002\u672c\u7ae0\u5c06\u5728 NixOS \u4e0a\u642d\u5efa\u4e00\u5957\u5b8c\u6574\u7684\u76d1\u63a7\u6808\uff1aPrometheus \u7528\u4e8e\u6307\u6807\u91c7\u96c6\uff0cGrafana \u7528\u4e8e\u4eea\u8868\u677f\u5c55\u793a\uff0cLoki \u7528\u4e8e\u65e5\u5fd7\u805a\u5408\u3002","sidebar":"tutorialSidebar"},"security-hardening":{"id":"security-hardening","title":"\u5b89\u5168\u52a0\u56fa","description":"TOTP \u4fdd\u62a4\u4e86 sudo\uff0c\u4f46\u751f\u4ea7\u73af\u5883\u7684 NixOS \u670d\u52a1\u5668\u9700\u8981\u5168\u9762\u7684\u5b89\u5168\u52a0\u56fa\u3002\u672c\u7ae0\u6db5\u76d6\u9632\u706b\u5899\u89c4\u5219\u3001SSH \u52a0\u56fa\u3001Fail2ban\u3001systemd \u670d\u52a1\u6c99\u7bb1\u5316\u4ee5\u53ca\u81ea\u52a8\u5b89\u5168\u66f4\u65b0\u2014\u2014\u6240\u6709\u914d\u7f6e\u90fd\u4ee5\u58f0\u660e\u5f0f\u65b9\u5f0f\u5728 Nix \u4e2d\u5b8c\u6210\u3002","sidebar":"tutorialSidebar"},"totp-sudo-protection":{"id":"totp-sudo-protection","title":"TOTP Sudo \u9632\u62a4","description":"This chapter configures TOTP (Time-based One-Time Password) authentication for sudo, ensuring that critical operations like nixos-rebuild switch require a 6-digit code from an authenticator app \u2014 even if an attacker gains shell access.","sidebar":"tutorialSidebar"}}}}')}}]);